import requests

BASE_URL = "http://localhost:4000"
LOGIN_ENDPOINT = "/api/v1/auth/login"
TIMEOUT = 30

def test_post_api_v1_auth_login_with_valid_credentials():
    url = BASE_URL + LOGIN_ENDPOINT
    headers = {
        "Content-Type": "application/json"
    }
    # Assuming valid credentials - replace with actual valid test credentials
    payload = {
        "email": "validuser@example.com",
        "password": "ValidPassword123!"
    }
    try:
        response = requests.post(url, json=payload, headers=headers, timeout=TIMEOUT)
    except requests.RequestException as e:
        assert False, f"Request failed: {e}"

    assert response.status_code == 200, f"Expected status code 200, got {response.status_code}"

    try:
        json_data = response.json()
    except ValueError:
        assert False, "Response is not valid JSON"

    assert isinstance(json_data, dict), "Response JSON is not an object"
    assert "accessToken" in json_data, "Response JSON does not contain JWT access token"

    # Check that the token value is a non-empty string
    token = json_data.get("accessToken")
    assert isinstance(token, str) and len(token) > 0, "JWT access token is not a non-empty string"

test_post_api_v1_auth_login_with_valid_credentials()

import requests

def test_post_api_v1_auth_login_with_invalid_credentials():
    base_url = "http://localhost:4000"
    endpoint = "/api/v1/auth/login"
    url = base_url + endpoint

    invalid_credentials = {
        "email": "invalid_user@example.com",
        "password": "wrong_password"
    }

    headers = {
        "Content-Type": "application/json"
    }

    try:
        response = requests.post(url, json=invalid_credentials, headers=headers, timeout=30)
    except requests.RequestException as e:
        assert False, f"Request failed: {e}"

    assert response.status_code == 401, f"Expected status code 401, got {response.status_code}"
    try:
        response_json = response.json()
    except ValueError:
        assert False, "Response is not in JSON format"

    # Check for an authentication error message in the response
    error_message = response_json.get("error") or response_json.get("message") or ""
    assert error_message, "Response JSON does not contain an error message"
    assert "unauthorized" in error_message.lower() or "invalid" in error_message.lower(), \
        f"Unexpected error message: {error_message}"

test_post_api_v1_auth_login_with_invalid_credentials()

